a,b,c = input().split()

if c == '+':
    print(int(a)+int(b))
elif c == '-':
    print(int(a)-int(b))
elif c == '*':
    print(int(a)*int(b))
elif c == '/':
    if int(b) == 0:
        print('Divided by zero!')
    else:
        print(int(int(a) / int(b)))
else:
    print('Invalid operator!')
